import { FormikProps } from 'formik';
import { useEffect, useRef, useState } from 'react';
import { BiTrash } from 'react-icons/bi';

export const Dropzone = ({ defaultImg, onDrop, onDelete, file }) => {
  const [preview, setPreview] = useState('');
  const ref = useRef<HTMLInputElement>(null);

  const onChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // if size is greater than 5MB
    if (file.size > 5 * 1024 * 1024) return alert('File size should be less than 5MB');

    // if file type is not image
    if (!file.type.includes('image')) return alert('Only images are allowed');

    setPreview(URL.createObjectURL(file));
    onDrop(file);
  };

  useEffect(() => {
    if (!file) return;
    if (file.type === undefined) return;
    if (!file.type.includes('image')) return;
    setPreview(URL.createObjectURL(file));
    onDrop(file);
  }, [file]);

  return (
    <div className="px-2 py-3">
      {/* <label className="fieldLabel">{label}</label> */}
      <div className="w-full h-[80px] border-2 border-gray-400 border-tertiary border-dashed rounded-xl flex items-center justify-center relative cursor-pointer overflow-hidden">
        <input
          type="file"
          className="text-[0] border-0 absolute inset-0 cursor-pointer opacity-0 z-[5]"
          title=""
          onChange={onChange}
          accept="image/*"
          multiple={false}
          ref={ref}
        />
        {preview || defaultImg ? (
          <div className="flex items-center justify-center">
            <img
              className="absolute inset-0 m-auto w-auto h-full !bg-no-repeat bg-center"
              src={preview || defaultImg}
              alt="Thumbnail"
            />
            <span
              className="w-10 h-10 flex items-center justify-center bg-white rounded-full z-10"
              onClick={() => {
                setPreview('');
                onDelete();
                if (ref.current) ref.current.value = '';
              }}
            >
              <BiTrash className="w-5 h-5 text-danger" />
            </span>
          </div>
        ) : (
          <span className="text-sm text-center text-dark">Drag and drop, or click to select</span>
        )}
      </div>
    </div>
  );
};
